};

// --- 通用選項 ---
const COMMON_A_OPTIONS = ['主動探視', '予以評估及觀察', '鼓勵表達感受', '澄清', '傾聽', '引導', '提供現實感', '告知現用藥之作用', '協助停餐'];
const COMMON_R_OPTIONS = ['予以傾聽下', '予以引導下', '病人可接受告知', '班內病人言談合宜', '暫未有提及其他不適之感受，病人可前來配合治療'];
const COMMON_D_OBSERVATIONS = [{ id: 'comm_d1', text: '病人多簡短切題回應', type: 'obs' }, { id: 'comm_d2', text: '病人多被動簡短回應', type: 'obs' }, { id: 'comm_d3', text: '病人可切題回應', type: 'obs' }];

// --- NANDA 資料庫 ---
const NANDA_FOCUS_DATA = {
    leave_absence: { 
        label: '請假外出', 
        subjective_tags: [], 
        actions: ['告知醫療團隊。', '同意病人請假外出四小時。', '協助填寫請假登記本。', '告知返室時間。', '告知外出注意事項。', '病人帶出13：00藥物。'], 
        responses: ['病人及○○表示可了解，持續追蹤病人返室時間', '病人現由○○陪同返室，外出期間未有提及不適之感受，可配合安檢，已服13：00藥物'], 
        teachings: [] 
    },
    sleep_pattern: {
        label: '睡眠型態改變',
        d_options: ['病人於22：00入睡', '無夜眠中斷', '夜眠中斷1次', '夜眠中斷時多於房內躺床', '可入睡至06：30晨醒', '可再度躺床至06：30晨醒', '可再躺床至05：30早醒', '觀其病人早醒時，', '夜眠總時數8.5小時。'],
        subjective_tags: [], actions: ['評估睡眠環境與干擾因素，維持夜間病房安靜。', '限制白天臥床時間，鼓勵日間活動消耗體力。', '睡前避免刺激性活動與飲料，可給予溫牛奶。', '依醫囑給予助眠藥物，並評估成效。'], responses: ['夜間能持續睡眠6小時以上，自述精神改善', '減少白天臥床頻率，能參與職能活動', '夜間未再頻繁起床，能安穩入睡'], teachings: ['衛教睡眠衛生原則(固定作息、床只留給睡覺用)。', '教導放鬆訓練助眠。']
    },
    risk_falls: { label: '高風險跌倒', d_options: ['病人多於大廳活動', '病人多於房內活動', '病人班內無夜眠中斷，暫無下床活動情形', '情緒尚可自控', '情緒偶起伏', '觀察活動時之步態緩慢尚穩', '步態不穩，需人攙扶', '使用輔具(輪椅/助行器)活動', '服用鎮靜安眠藥物後，精神顯倦怠', '更換姿勢時出現姿位性低血壓'], subjective_tags: [], actions: ['定時探視。', '密切觀察病人之動態、情緒及行為反應。', '評估及觀察步態。', '於病人手圈貼上防跌標籤。', '維持病室地面乾燥淨空，常用物品置於隨手可得處。'], responses: ['病人可接受告知，班內暫未見有跌倒之情形', '班內暫未見有跌倒之情形', '下床活動時會先按鈴求助，未發生跌倒'], teachings: ['衛教變換姿勢應緩慢，預防姿勢性低血壓。', '教導穿著合適防滑鞋襪的重要性。'] },
    send_exam: { label: '送檢查', subjective_tags: [], actions: ['協助聯絡送檢事宜，由○○及轉送人員陪伴下步行至檢查室。'], responses: ['持續追蹤病人返室情形', '病人現由○○及2位轉送人員陪同下以步行方式返室，外檢期間未有抱怨不適感受，可配合安檢'], teachings: [] },
    admission_care: { label: '入院護理', d_templates: ['病人經醫師評估下，建議住院治療，故從急診由2位EMT人員及○○的陪同下，以步行方式進入精神專科病房續照護。', '病人由2位EMT人員從急診步行入病房，有家屬陪伴，外觀合宜，態度合作，說明後可配合安檢。'], subjective_tags: [], actions: ['聯絡醫師、測量生命徵象、執行入院護理及身體評估、給予環境介紹。'], responses: ['○○及病人可了解衛教內容。'], teachings: ['教導叫人鈴及陪病證使用、貴重物品自行保管、本院全面禁菸、會客規則。'] },
    visitation: { label: '會客', subjective_tags: [], actions: ['告知醫療團隊。', '協助安排會客空間。', '觀察病人與家屬互動情形。', '提醒家屬會客注意事項及違禁品規定。'], responses: ['病人與家屬互動良好，情緒平穩', '家屬配合病房規定，準時結束會客', '病人表示很高興家人來看他'], teachings: ['衛教家屬與病人溝通之技巧。', '提醒家屬下次會客時間。'] },
    restraint_limbs: { label: '四肢約束', reasons: ['預防跌倒', '暴力行為', '自殺傷行為', '情緒激動', '自行要求'], d_templates: ['現病人因○○於治療室自願性四肢約束', '予以探視及關心時', '病人未有抱怨不適感受', '病人閉眼入睡，呼吸平順', '病人可配合服藥', '予以協助更換姿勢', '予以評估下，病人四肢約束部位皮膚溫暖，循環可', '予以評估下，病人四肢約束帶保護性約束，鬆緊度可塞入1-2指，約束肢體末梢皮膚溫暖、膚色及血液循環正常、脈搏++、約束部位皮膚完整無破損，約束帶固定於床架，每兩小時協助翻身並檢查尿布', '續觀病人情緒及行為變化', '病人現因○○於治療室自願性四肢約束中'], subjective_tags: [], actions: ['每15分鐘探視病人，觀察約束部位血液循環及皮膚狀況。', '每2小時協助翻身、更換姿勢及活動肢體。', '評估病人基本生理需求(如飲水、如廁)。', '維持約束部位功能性位置，鬆緊度適宜(容納1-2指)。'], responses: ['約束部位皮膚完整無破損，末梢循環良好', '病人情緒漸趨平穩，能配合護理指導', '經評估後暫時維持約束，持續觀察'], teachings: ['向家屬解釋約束之目的與保護性質。', '指導家屬協助病人肢體活動之技巧。'] },
    thought_process: { label: '思考過程失調', subjective_tags: [{ id: 'sub_th_del', text: '我是美國總統，FBI都在追我(誇大/被害)' }, { id: 'sub_th_broad', text: '我的想法都被廣播出來了' }, { id: 'sub_th_control', text: '大腦被外星人控制植入晶片' }, { id: 'sub_th_loose', text: '講話跳躍，無法對焦' }], actions: ['提供現實導向，不與其爭辯妄想內容的真實性。', '以具體、簡短的語句溝通，避免過度抽象。', '建立規律作息，減少環境中的混亂刺激。', '依醫囑給予抗精神病藥物，並確認藥物確實吞服。'], responses: ['暫無觀察病人有自語及自笑之情形', '續觀病人精神症狀', '班內否認有症狀干擾', '現續觀察病人之精神症狀', '能暫時轉移注意力參與活動，減少談論妄想內容', '雖仍有怪異想法，但情緒受影響程度減輕', '言語表達較切題，能回答簡單生活問題', '能區辨「這是我的想法」與「現實狀況」的差異'], teachings: ['衛教按時服藥對穩定腦部內分泌的重要性。', '指導現實感測試技巧(向信任的人核對)。'] },
    sensory_perception: { label: '感覺/知覺異常', subjective_tags: [{ id: 'sub_sen_voice', text: '你有聽到那個罵我的聲音嗎？' }, { id: 'sub_sen_bug', text: '牆上有蟲在爬/身上有蟲' }, { id: 'sub_sen_smell', text: '這裡有毒氣的味道' }, { id: 'sub_sen_cmd', text: '聲音叫我不要吃藥' }], actions: ['評估幻覺內容(特別是命令式幻聽)及危險性。', '適時呈現現實原則：「我沒聽到聲音，但我知道你很困擾。」', '減少環境噪音刺激，安排安靜的休息空間。', '觀察幻覺出現頻率，介入干擾技巧(如對話)。'], responses: ['暫無觀察病人有自語及自笑之情形', '續觀病人精神症狀', '班內否認有症狀干擾', '現續觀察病人之精神症狀', '表示聲音變小了，受干擾程度降低', '能分辨聲音是症狀表現，未受其指令行事', '能運用聽音樂方式轉移幻覺注意力', '自言自語行為減少，能專注於當下活動'], teachings: ['教導干擾幻聽的技巧(如大聲朗讀、聽音樂、告訴聲音走開)。', '強調藥物治療對控制幻覺的重要性。'] },
    violence_other: { label: '高風險暴力行為(朝向他人)', subjective_tags: [{ id: 'sub_vio_kill', text: '我要殺了那個聲音的主人' }, { id: 'sub_vio_warning', text: '別靠近我否則不客氣' }, { id: 'sub_vio_unsafe', text: '這裡很不安全，有人要害我' }, { id: 'sub_vio_anger', text: '我很生氣，沒辦法控制自己' }, { id: 'sub_vio_demand', text: '叫醫生馬上讓我出院' }], actions: ['每班每15分鐘密切觀察病人動態;情緒;行為暴力徵兆,並記錄。', '主動傳達關心、傾聽、支持並鼓勵病人表達感受。', '減少不必要的環境刺激。', '不和病人爭辯，並在常規活動、處置、檢查前給予說明。', '引導不具傷害性的情緒宣洩方式、適當言語表達。', '移除環境中潛在危險物品(如熱水瓶、金屬銳器)，維持安全護理環境。', '採堅定態度設限，明確告知暴力行為不被接受。', '維持適當身體距離，避免背對病人或採取威脅姿態。', '依醫囑給予化學性約束(針劑/口服藥)，並觀察鎮靜效果。', '請求人力支援，予以說明其約束原因後，依醫囑執行身體約束或保護隔離。'], responses: ['暴力風險評估BVC分數為？分', '經處置後情緒激動緩解，無攻擊行為發生', '能遵守病房規範，與人互動時保持安全距離', '表示憤怒時會先尋求工作人員協助'], teachings: ['教導衝動控制技巧與衝突情境的暫停(Time-out)策略。', '指導以深呼吸緩解當下的肌肉緊繃。', '教導以語言表達不滿，取代肢體暴力。'] },
    violence_self: { label: '高風險暴力行為(朝向自己)', subjective_tags: [{ id: 'sub_suicide_die', text: '活著沒意義，想死了一了百了' }, { id: 'sub_suicide_voice', text: '有聲音叫我去死' }, { id: 'sub_suicide_hopeless', text: '我是家裡的負擔，沒有希望了' }, { id: 'sub_suicide_plan', text: '我已經想好怎麼做了' }], actions: ['每班每15分鐘密切觀察病患動態;情緒;行為;自傷自殺徵兆;原因;分級;並記錄交班。', 'Grade1；一、每週一次進行安檢；二、限制物品在准許下使用；三、可使用一般餐具。', '協助病人能以合宜方式表達需求及處理挫折方法。', '衛教引導出現自傷自殺處理方式；因應方法。', '引導合宜的情緒宣洩方；哭泣、安排活動、搥打枕頭、床墊、適當言語表達。', '提供關懷及支持，同理其無奈、失落、無助感受。', '執行自殺/自傷防範措施，收走銳器、長繩及危險物品。', '與病人簽署不自殺/不自傷契約，建立承諾。'], responses: ['評估自殺傷分級Grade1為:？', '否認有自殺意念，並簽署不自殺契約', '能主動向護理師表達負面情緒，未出現自傷行為', '情緒較平穩，承諾會配合治療'], teachings: ['教導情緒低落時的求助管道與資源。', '指導轉移注意力技巧以度過衝動期。'] },
    ineffective_coping: { label: '因應能力失調-個人', subjective_tags: [{ id: 'sub_cop_drug', text: '一煩我就想吸毒/喝酒' }, { id: 'sub_cop_giveup', text: '我不知道該怎麼辦，隨便啦' }, { id: 'sub_cop_manip', text: '你不給我打電話我就不吃藥' }], actions: ['協助病人辨識引發壓力的情境與誘發因子。', '討論過去失敗的因應方式(如物質濫用)及其後果。', '設定行為契約，對正向行為給予增強，忽略操控行為。', '鼓勵並引導嘗試新的壓力調適策略(如運動、書寫)。'], responses: ['能說出兩種正向的壓力調適方法', '面對挫折時未出現衝動行為，能主動求助', '願意配合治療計畫，減少討價還價的操控行為'], teachings: ['教導問題解決步驟(確認問題->列出方案->評估後果)。', '指導壓力管理與情緒宣洩的合宜方式。'] },
    anxiety: { label: '焦慮', subjective_tags: [{ id: 'sub_anx_die', text: '我心跳好快，覺得快要死掉了' }, { id: 'sub_anx_worry', text: '我很緊張，坐不住' }, { id: 'sub_anx_whatif', text: '萬一發生這種事怎麼辦...' }], actions: ['採主動傾聽，維持冷靜且接納的態度陪伴。', '將病人帶至安靜、低刺激的環境。', '教導並引導執行腹式呼吸或肌肉放鬆技巧。', '使用簡短、具體的語句說明，減輕認知負荷。', '提供保證(Reassurance)，告知目前環境是安全的。'], responses: ['練習放鬆技巧後，自述焦慮感減輕', '生命徵象平穩，肢體放鬆，能安穩坐著', '停止來回踱步，能專注聆聽護理指導'], teachings: ['教導焦慮緩解技巧(深呼吸、正念冥想)。', '衛教避免攝取咖啡因等刺激性飲品。'] },
    discharge_planning: { label: '出院照護指導', subjective_tags: [{ id: 'sub_dis_med', text: '回家後藥要怎麼吃？' }, { id: 'sub_dis_home', text: '擔心回家會復發/睡不著' }, { id: 'sub_dis_res', text: '我不想要去康復之家' }], actions: ['討論疾病症狀認知及罹病後感受。', '說明目前使用藥物種類，討論用藥後帶來的幫助及變化。', '指導憂鬱症急性症狀及穩定後的型態。', '指導壓力會對疾病帶來什麼影響。', '進行睡眠衛生指導，說明藥物的有效輔助。', '討論過往壓力因應模式，尋找適用且實用的技巧重複練習並執行。', '評估病人對自身疾病與藥物的認知程度。', '詳細解說藥物名稱、作用、副作用及服用時間(提供藥卡)。', '核對出院帶藥，請病人覆誦服用方式。'], responses: ['能正確說出藥物服用方式及注意事項', '收下衛教單張，表示了解重點', '持有預約回診單，承諾準時回診'], teachings: ['衛教自行停藥之風險及復發徵兆(如睡眠減少、情緒波動)。', '強調規律作息與不飲酒的重要性。'] }
};

const MSE_COMMON_DATA = {
