// --- 交班未完成事項提醒視窗 ---
const ShiftHandoverCheckModal = ({ onClose, handoverList, setHandoverList }) => {
    const [isMinimized, setIsMinimized] = useState(false);
    const incompleteItems = handoverList.filter(i => i.record === 1 || i.assess === 1 || i.observe === 1);
    const isAllDone = incompleteItems.length === 0;

    const toggleStatus = (id, field) => {
        setHandoverList(prev => prev.map(item => {
            if (item.id === id) {
                if (item[field] === 1) return { ...item, [field]: 2 };
                if (item[field] === 2) return { ...item, [field]: 1 };
            }
            return item;
        }));
    };

    if (isMinimized) {
        return (
            <div className="fixed bottom-20 right-4 z-[70] animate-pulse cursor-pointer" onClick={() => setIsMinimized(false)}>
                <div className="bg-red-500 text-white p-4 rounded-full shadow-lg border-4 border-white flex items-center gap-2 hover:scale-110 transition-transform">
                    <ListChecks size={32} />
                    <span className="font-bold text-xs text-center leading-tight">交班<br/>未完</span>
                </div>
            </div>
        );
    }

    return (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-[70] p-4 animate-fade-in">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col border-t-8 border-red-500">
                <div className="p-4 border-b border-slate-100 flex justify-between items-center">
                     <div className="flex items-center gap-2 text-red-600">
                        <AlertTriangle size={24} />
                        <h3 className="text-xl font-bold">交班事項未完成提醒</h3>
                     </div>
                     <button onClick={() => setIsMinimized(true)} className="text-slate-400 hover:text-slate-600"><Minimize2 size={20}/></button>
                </div>
                <div className="flex-1 overflow-y-auto p-6">
                    {isAllDone ? (
                        <div className="text-center py-10 text-green-600 flex flex-col items-center gap-2"><CheckSquare size={48} /><span className="text-xl font-bold">太棒了！所有事項已完成。</span></div>
                    ) : (
                        <div className="space-y-4">
                            <p className="text-slate-600 font-bold">以下床號仍有未完成事項，請點擊確認完成：</p>
                            {incompleteItems.map(item => (
                                <div key={item.id} className="bg-red-50 border border-red-100 rounded-lg p-3 flex items-center justify-between">
                                    <span className="font-bold text-lg text-red-800 w-16">床 {item.bed || '?'}</span>
                                    <div className="flex gap-4">
                                        {item.record === 1 && <button onClick={() => toggleStatus(item.id, 'record')} className="flex items-center gap-1 px-3 py-1 bg-white border border-red-200 rounded text-red-600 hover:bg-red-100"><Square size={16}/> 護理紀錄</button>}
                                        {item.assess === 1 && <button onClick={() => toggleStatus(item.id, 'assess')} className="flex items-center gap-1 px-3 py-1 bg-white border border-red-200 rounded text-red-600 hover:bg-red-100"><Square size={16}/> 身心評估</button>}
                                        {item.observe === 1 && <button onClick={() => toggleStatus(item.id, 'observe')} className="flex items-center gap-1 px-3 py-1 bg-white border border-red-200 rounded text-red-600 hover:bg-red-100"><Square size={16}/> 密觀單</button>}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
                <div className="p-4 border-t border-slate-100 flex gap-3 justify-end">
                    <button onClick={() => setIsMinimized(true)} className="px-4 py-2 text-slate-500 hover:bg-slate-100 rounded-lg font-bold">稍後處理 (縮小)</button>
                    <button onClick={isAllDone ? onClose : undefined} className={`px-6 py-2 rounded-lg font-bold text-white transition-colors ${isAllDone ? 'bg-green-600 hover:bg-green-700' : 'bg-slate-300 cursor-not-allowed'}`}>已全部完成</button>
                </div>
