// --- 每日提醒 + 班別切換 ---
const DailyReminder = ({ currentShift, setCurrentShift, onOpenHandover }) => {
  const [today, setToday] = useState(new Date());
  const [checkState, setCheckState] = useState(false); 

  useEffect(() => {
    setToday(new Date());
  }, []);

  const dayIndex = today.getDay(); 
  const dateString = today.toLocaleDateString('zh-TW', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' });
  const reminders = WEEKDAY_REMINDERS[dayIndex] || [];

  const toggleShift = () => {
      const next = currentShift === 'A' ? 'E' : currentShift === 'E' ? 'N' : 'A';
      setCurrentShift(next);
  };

  const shift = SHIFT_SETTINGS[currentShift];

  return (
    <div className="bg-indigo-50 border-b border-indigo-100 px-4 py-2 flex flex-col md:flex-row md:items-center gap-4 text-sm text-indigo-900 justify-between">
        <div className="flex items-center gap-4 flex-grow">
            <div className="flex items-center gap-2 font-bold whitespace-nowrap">
                <Calendar size={16} className="text-indigo-600"/>
                {dateString}
            </div>
            <div className="h-4 w-px bg-indigo-200 hidden md:block"></div>
            <div className="flex flex-wrap gap-3 items-center">
                <span className="font-bold text-indigo-500 text-xs uppercase tracking-wider">今日提醒:</span>
                {reminders.length > 0 ? reminders.map((item, idx) => (
                    <div key={idx} className="flex items-center gap-1.5 bg-white px-2 py-1 rounded border border-indigo-100 shadow-sm">
                        {item.type === 'check' ? (
                            <button onClick={() => setCheckState(!checkState)} className={`flex items-center gap-1 ${checkState ? 'text-green-600 font-bold line-through opacity-50' : 'text-indigo-800'}`}>
                                {checkState ? <CheckSquare size={14}/> : <Square size={14}/>} {item.content}
                            </button>
                        ) : <span className="text-indigo-800">{item.content}</span>}
                    </div>
                )) : <span className="text-indigo-400 italic">無</span>}
            </div>
        </div>

        <div className="flex items-center gap-3">
            <button 
                onClick={toggleShift}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full border text-xs font-bold shadow-sm transition-all hover:scale-105 ${shift.color}`}
                title="點擊切換班別"
            >
                {shift.icon} {shift.label}
            </button>
            <button 
                onClick={onOpenHandover}
                className="bg-indigo-600 hover:bg-indigo-700 text-white px-3 py-1.5 rounded text-xs font-bold flex items-center gap-1 transition-colors shadow-sm whitespace-nowrap"
            >
                <ListChecks size={14}/> 交班單
            </button>
        </div>
    </div>
  );
};

const ChecklistModal = ({ onClose }) => {
    const [checkedItems, setCheckedItems] = useState({});
    const [isMinimized, setIsMinimized] = useState(false);
    const [highlightItem, setHighlightItem] = useState(null);

    const allItems = [
      ...ADMISSION_CHECKLIST.before.map((text, i) => ({ id: `before-${i}`, text, type: 'before' })),
      ...ADMISSION_CHECKLIST.after.map((text, i) => ({ id: `after-${i}`, text, type: 'after' }))
    ];

    const totalCount = allItems.length;
    const checkedCount = Object.values(checkedItems).filter(Boolean).length;
    const progress = Math.round((checkedCount / totalCount) * 100);

    const toggleCheck = (id) => {
      setCheckedItems(prev => ({...prev, [id]: !prev[id]}));
      if (highlightItem === id) setHighlightItem(null);
    };

    const handleComplete = () => {
      const firstUnchecked = allItems.find(item => !checkedItems[item.id]);
      if (firstUnchecked) {
        setHighlightItem(firstUnchecked.id);
        const element = document.getElementById(firstUnchecked.id);
        if (element) element.scrollIntoView({ behavior: 'smooth', block: 'center' });
      } else {
        onClose();
      }
    };

    if (isMinimized) {
      return (
        <div className="fixed bottom-4 right-4 z-50 animate-pulse cursor-pointer" onClick={() => setIsMinimized(false)}>
          <div className="bg-yellow-400 text-yellow-900 p-4 rounded-full shadow-lg border-4 border-white flex items-center gap-2 hover:scale-110 transition-transform">
             <ClipboardCheck size={32} />
             <span className="font-bold text-sm">檢核中...<br/>({progress}%)</span>
          </div>
        </div>
      );
    }

    return (
      <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 animate-fade-in p-4">
        <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[90vh] flex flex-col overflow-hidden">
          <div className="bg-blue-600 p-4 rounded-t-xl flex justify-between items-center shrink-0">
            <div className="flex items-center gap-3 text-white">
              <ClipboardCheck size={24} />
              <div><h3 className="text-lg font-bold leading-none">入院護理檢核表</h3><span className="text-xs text-blue-200">完成度: {checkedCount} / {totalCount}</span></div>
            </div>
            <button onClick={() => setIsMinimized(true)} className="text-blue-100 hover:text-white p-1 rounded hover:bg-blue-500 transition-colors" title="縮小"><Minimize2 size={20} /></button>
          </div>
          <div className="h-1.5 w-full bg-slate-100"><div className="h-full bg-green-500 transition-all duration-500 ease-out" style={{ width: `${progress}%` }}></div></div>
          <div className="overflow-y-auto p-6 space-y-6 bg-slate-50">
            <section>
              <h4 className="text-blue-800 font-bold text-base border-b-2 border-blue-100 pb-2 mb-3 flex items-center gap-2 sticky top-0 bg-slate-50 z-10">
                <span className="bg-blue-100 text-blue-600 px-2 py-0.5 rounded text-xs">Step 1</span> 入院前準備
              </h4>
              <div className="space-y-2">
                {ADMISSION_CHECKLIST.before.map((text, idx) => {
                  const id = `before-${idx}`;
                  const isHighlighted = highlightItem === id;
                  return (
                      <div key={id} id={id} onClick={() => toggleCheck(id)} className={`flex items-start gap-3 p-3 rounded-lg cursor-pointer transition-all border ${isHighlighted ? 'bg-red-50 border-red-300 animate-pulse' : checkedItems[id] ? 'bg-blue-50 border-blue-100' : 'bg-white border-transparent hover:border-slate-200 shadow-sm'}`}>
