              </h4>
              <div className="space-y-2">
                {ADMISSION_CHECKLIST.after.map((text, idx) => {
                  const id = `after-${idx}`;
                  const isHighlighted = highlightItem === id;
                  return (
                      <div key={id} id={id} onClick={() => toggleCheck(id)} className={`flex items-start gap-3 p-3 rounded-lg cursor-pointer transition-all border ${isHighlighted ? 'bg-red-50 border-red-300 animate-pulse' : checkedItems[id] ? 'bg-green-50 border-green-100' : 'bg-white border-transparent hover:border-slate-200 shadow-sm'}`}>
                        <div className={`mt-1 shrink-0 transition-colors ${checkedItems[id] ? 'text-green-600' : isHighlighted ? 'text-red-500' : 'text-slate-300'}`}>{checkedItems[id] ? <CheckSquare size={20} /> : <Square size={20} />}</div>
                        <div className="flex-grow"><span className={`text-sm leading-relaxed block ${checkedItems[id] ? 'text-slate-500 line-through' : isHighlighted ? 'text-red-600 font-bold' : 'text-slate-700 font-medium'}`}>{text}</span>{isHighlighted && <span className="text-xs text-red-500 font-bold mt-1 block">← 請確認此項目！</span>}</div>
