    const subItems = NANDA_FOCUS_DATA[selectedFocus]?.subjective_tags?.filter(t => selectedSubjective.includes(t.id)).map(t => t.text) || [];
    const commonSub = COMMON_D_OBSERVATIONS.filter(t => selectedSubjective.includes(t.id)).map(t => t.text);
    let allSub = [...subItems, ...commonSub];
    if (customSubjective) allSub.push(customSubjective);

    if (allSub.length) baseD += `，予以探視及關心時，病人表示：「${allSub.join('，')}」。`;

    setRecord(prev => ({ ...prev, D: baseD }));
  }, [selectedMSE, selectedSubjective, selectedFocus, visitorName, fallsD, sleepD, customSubjective, medicalTeamType]);

  const toggle = (id, list, setFn) => setFn(list.includes(id) ? list.filter(x=>x!==id) : [...list, id]);
  const addText = (f, t) => setRecord(p => ({...p, [f]: p[f].includes(t)? p[f]: p[f]+'\n'+t})); 
  const copyAll = () => {}; 
  const handleAiPolishD = () => {}; 
