      </div>

      <div className="flex flex-1 overflow-hidden w-full">
        <div className="w-1/3 bg-white border-r border-slate-200 flex flex-col min-h-0">
             {showInputBox ? (
                 <div className="p-3 flex flex-col gap-3 h-full">
