                     {selectedFocus === 'leave_absence' && (
                        <div className="mt-2 bg-slate-50 p-2 rounded border border-slate-200">
                            <label className="block text-xs font-bold text-slate-600 mb-1">醫療團隊選擇:</label>
                            <div className="flex gap-3">
                                <label className="flex items-center gap-1 text-xs cursor-pointer hover:text-blue-600">
                                    <input type="radio" name="teamType" value="值班醫療團隊" checked={medicalTeamType === '值班醫療團隊'} onChange={e => setMedicalTeamType(e.target.value)} className="text-blue-600"/>
