                                </label>
                                <label className="flex items-center gap-1 text-xs cursor-pointer hover:text-blue-600">
                                    <input type="radio" name="teamType" value="醫療團隊" checked={medicalTeamType === '醫療團隊'} onChange={e => setMedicalTeamType(e.target.value)} className="text-blue-600"/>
                                    醫療團隊
