                         {NANDA_FOCUS_DATA[selectedFocus]?.actions?.map((t,i)=><button key={i} onClick={()=>addText('A',t)} className="text-xs text-left p-1.5 hover:bg-red-50 rounded text-slate-700 leading-snug">+ {t.replace('○○',visitorName||'○○')}</button>)}
                    </div>
                </div>
