                    <div className="px-2 py-1 bg-green-50 text-green-800 text-[10px] font-bold">R (反應)</div>
                    <div className="p-1 flex flex-col gap-0.5">
                        <div className="border-b border-green-50 pb-1 mb-1 flex flex-wrap gap-1">{COMMON_R_OPTIONS.map((t,i)=><button key={i} onClick={()=>addText('R',t)} className="text-[10px] bg-slate-50 border px-1.5 py-0.5 rounded hover:bg-green-100 truncate max-w-full">• {t}</button>)}</div>
                        {NANDA_FOCUS_DATA[selectedFocus]?.responses?.map((t,i)=><button key={i} onClick={()=>addText('R',t)} className="text-xs text-left p-1.5 hover:bg-green-50 rounded text-slate-700 leading-snug">+ {t.replace('○○',visitorName||'○○')}</button>)}
                    </div>
                </div>
                {NANDA_FOCUS_DATA[selectedFocus]?.teachings?.length > 0 && (
                    <div className="bg-white rounded border border-amber-100 overflow-hidden">
                        <div className="px-2 py-1 bg-amber-50 text-amber-800 text-[10px] font-bold">T (衛教)</div>
                        <div className="p-1 flex flex-col gap-0.5">
                            {NANDA_FOCUS_DATA[selectedFocus].teachings.map((t,i)=><button key={i} onClick={()=>addText('T',t)} className="text-xs text-left p-1.5 hover:bg-amber-50 rounded text-slate-700 leading-snug">+ {t}</button>)}
                        </div>
                    </div>
                )}
