        {/* Right: Output */}
        <div className="w-1/3 bg-white flex flex-col min-h-0">
            <div className="p-2 bg-slate-800 text-white font-bold text-xs flex justify-between items-center"><span>紀錄預覽</span><button onClick={copyAll} className="bg-green-600 px-2 py-0.5 rounded hover:bg-green-500">複製</button></div>
            <div className="flex-1 p-2 space-y-2 overflow-y-auto custom-scrollbar flex flex-col">
                <div className="border rounded p-1 shadow-sm flex flex-col flex-[2] min-h-[80px]">
                    <div className="flex justify-between px-1 mb-1"><span className="text-[10px] font-bold text-blue-600">D: Data</span><button onClick={handleAiPolishD} className="text-[10px] text-blue-500 flex items-center gap-0.5 hover:bg-blue-50 rounded px-1"><Sparkles size={8}/> 修飾</button></div>
                    <textarea value={record.D} onChange={e=>setRecord({...record,D:e.target.value})} className="w-full flex-1 text-sm outline-none resize-none p-1"/>
                </div>
                <div className="border rounded p-1 shadow-sm flex flex-col flex-1 min-h-[60px]">
                    <div className="text-[10px] font-bold text-red-600 px-1 mb-1">A: Action</div>
                    <textarea value={record.A} onChange={e=>setRecord({...record,A:e.target.value})} className="w-full flex-1 text-sm outline-none resize-none p-1"/>
                </div>
                <div className="border rounded p-1 shadow-sm flex flex-col flex-1 min-h-[60px]">
                    <div className="text-[10px] font-bold text-green-600 px-1 mb-1">R: Response</div>
                    <textarea value={record.R} onChange={e=>setRecord({...record,R:e.target.value})} className="w-full flex-1 text-sm outline-none resize-none p-1"/>
                </div>
                <div className="border rounded p-1 shadow-sm flex flex-col flex-1 min-h-[60px]">
                    <div className="text-[10px] font-bold text-amber-600 px-1 mb-1">T: Teaching</div>
                    <textarea value={record.T} onChange={e=>setRecord({...record,T:e.target.value})} className="w-full flex-1 text-sm outline-none resize-none p-1"/>
                </div>
            </div>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background-color: #cbd5e1; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background-color: #94a3b8; }
      `}</style>
    </div>
  );
};

export default PsychNursingProV35;

