import { Clipboard, Trash2, Brain, Layers, Activity, ChevronDown, ChevronUp, FileText, Stethoscope, User, Lock, Ambulance, LogIn, Bell, X, Calendar, CheckSquare, Square, AlertTriangle, Sparkles, Loader2, Moon, ClipboardCheck, Minimize2, Maximize2, ListChecks, Clock, PlusCircle, MinusCircle, AlarmClock, Sun, Sunset, Moon as MoonIcon, Copy, Syringe, Pill, LocateFixed, MoreHorizontal } from 'lucide-react';
