import React, { useState, useEffect } from 'react';
import { Calendar, CheckSquare, Square, ListChecks } from 'lucide-react';
import { WEEKDAY_REMINDERS, SHIFT_SETTINGS } from '../constants';
import { ShiftType } from '../types';

interface Props {
    currentShift: ShiftType;
    setCurrentShift: (shift: ShiftType) => void;
    onOpenHandover: () => void;
}

const DailyReminder: React.FC<Props> = ({ currentShift, setCurrentShift, onOpenHandover }) => {
    const [currentTime, setCurrentTime] = useState(new Date());
    const [checkState, setCheckState] = useState(false);

    useEffect(() => {
        const timer = setInterval(() => setCurrentTime(new Date()), 1000);
        return () => clearInterval(timer);
    }, []);

    const dayIndex = currentTime.getDay();
    const dateString = currentTime.toLocaleDateString('zh-TW', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' });
    const timeString = currentTime.toLocaleTimeString('zh-TW', { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' });
    const reminders = WEEKDAY_REMINDERS[dayIndex] || [];

    const toggleShift = () => {
        const next = currentShift === 'A' ? 'E' : currentShift === 'E' ? 'N' : 'A';
        setCurrentShift(next);
    };

    const shift = SHIFT_SETTINGS[currentShift];

    return (
        <div className="flex flex-col md:flex-row md:items-center gap-4 text-base text-slate-700 justify-between">
            <div className="flex items-center gap-6 flex-grow bg-white/40 px-4 py-2 rounded-2xl border border-white/50 backdrop-blur-sm shadow-sm">
                <div className="flex flex-col">
                    <div className="flex items-center gap-2 font-bold whitespace-nowrap leading-tight text-slate-600">
                        <Calendar size={16} className="text-indigo-500" />
                        {dateString}
                    </div>
                    <div className="text-sm font-mono font-bold text-indigo-500 ml-6 leading-none">
                        {timeString}
                    </div>
                </div>
                <div className="h-8 w-px bg-slate-300/50 hidden md:block"></div>
                <div className="flex flex-wrap gap-3 items-center">
                    <span className="font-bold text-indigo-500 text-xs uppercase tracking-wider hidden lg:inline bg-indigo-50 px-2 py-0.5 rounded-md">TODAY</span>
                    {reminders.length > 0 ? reminders.map((item, idx) => (
                        <div key={idx} className="flex items-center gap-1.5 bg-white/60 px-3 py-1 rounded-lg border border-white/60 shadow-sm backdrop-blur-md">
                            {item.type === 'check' ? (
                                <button onClick={() => setCheckState(!checkState)} className={`flex items-center gap-1.5 transition-all ${checkState ? 'text-green-600 font-bold line-through opacity-50' : 'text-slate-700'}`}>
                                    {checkState ? <CheckSquare size={16} /> : <Square size={16} />} {item.content}
                                </button>
                            ) : <span className="text-slate-700 font-medium">{item.content}</span>}
                        </div>
                    )) : <span className="text-slate-400 italic text-sm">無提醒</span>}
                </div>
            </div>

            <div className="flex items-center gap-3">
                <button
                    onClick={toggleShift}
                    className={`glass-button flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold shadow-sm transition-all hover:scale-105 active:scale-95 ${shift.color.replace('bg-', 'bg-opacity-20 ')}`}
                    title="點擊切換班別"
                    style={{ background: 'rgba(255,255,255,0.5)', borderColor: 'rgba(255,255,255,0.6)' }}
                >
                    {shift.icon} <span className="text-slate-700">{shift.label}</span>
                </button>
                <button
                    onClick={onOpenHandover}
                    className="bg-indigo-600/90 backdrop-blur-md hover:bg-indigo-700 text-white px-5 py-2 rounded-xl text-sm font-bold flex items-center gap-2 transition-all shadow-lg hover:shadow-indigo-500/30 whitespace-nowrap active:scale-95"
                >
                    <ListChecks size={18} /> 交班單
                </button>
            </div>
        </div>
    );
};

export default DailyReminder;

import React, { useState } from 'react';
import { ListChecks, X, PlusCircle, MinusCircle, AlarmClock, Clock } from 'lucide-react';
import { HandoverItem, ExamItem } from '../types';
import StatusIcon from './StatusIcon';

interface Props {
    onClose: () => void;
    handoverList: HandoverItem[];
    setHandoverList: React.Dispatch<React.SetStateAction<HandoverItem[]>>;
    examList: ExamItem[];
    setExamList: React.Dispatch<React.SetStateAction<ExamItem[]>>;
}

const HandoverModal: React.FC<Props> = ({ onClose, handoverList, setHandoverList, examList, setExamList }) => {
    const [newExam, setNewExam] = useState<{ bed: string; name: string; time: string }>({ bed: '', name: '', time: '' });

    const toggleStatus = (id: number, field: 'record' | 'assess' | 'observe') => {
        setHandoverList(prev => prev.map(item => {
            if (item.id === id) {
                const nextStatus = (item[field] + 1) % 3;
                return { ...item, [field]: nextStatus };
            }
            return item;
        }));
    };

    const updateField = (id: number, field: keyof HandoverItem, val: string) => {
        setHandoverList(prev => prev.map(item => item.id === id ? { ...item, [field]: val, alerted: false } : item));
    };

    const addRow = () => setHandoverList([...handoverList, { id: Date.now(), bed: '', record: 0, assess: 0, observe: 0, reminder: '', reminderTime: '', alerted: false }]);
    const removeRow = (id: number) => setHandoverList(prev => prev.filter(item => item.id !== id));

    const addExam = () => {
        if (newExam.bed && newExam.name && newExam.time) {
            setExamList([...examList, { ...newExam, id: Date.now(), alerted: false }]);
            setNewExam({ bed: '', name: '', time: '' });
        }
    };
    const removeExam = (id: number) => setExamList(prev => prev.filter(x => x.id !== id));

    return (
        <div className="fixed inset-0 bg-slate-900/30 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-fade-in">
