                                const id = `before-${idx}`;
                                const isHighlighted = highlightItem === id;
                                return (
                                    <div key={id} id={id} onClick={() => toggleCheck(id)} className={`flex items-start gap-4 p-4 rounded-2xl cursor-pointer transition-all border duration-300 ${isHighlighted ? 'bg-red-50/80 border-red-400 shadow-[0_0_15px_rgba(248,113,113,0.4)] scale-105' : checkedItems[id] ? 'bg-blue-50/50 border-blue-200' : 'bg-white/60 border-white/60 hover:bg-white/80 hover:shadow-md'}`}>
