            setRecord(prev => ({ 
                ...prev, 
                A: (prev.A ? prev.A + '\n' : '') + aiText + "\n(AI 建議)", 
                R: (prev.R ? prev.R + '，' : '') + " (請參考 AI 建議)" 
            }));
