                     <div className="flex-1 space-y-2">
                        {(showFallsBox ? NANDA_FOCUS_DATA.risk_falls : NANDA_FOCUS_DATA.sleep_pattern).d_options?.map(o => (
                            <button key={o} onClick={()=>toggle(o, showFallsBox?fallsD:sleepD, showFallsBox?setFallsD:setSleepD)} className={`text-sm text-left w-full p-3 rounded-xl border transition-all ${ (showFallsBox?fallsD:sleepD).includes(o) ? 'bg-slate-700 text-white shadow-lg' : 'bg-white/40 border-white/40 hover:bg-white/60 text-slate-700'}`}>{o}</button>
                        ))}
                     </div>
                 </div>
             ) : (
                 <>
                    {/* MSE Tabs */}
                    <div className="flex flex-col h-1/2 min-h-0">
                        <div className="shrink-0 border-b border-white/20 bg-white/10 backdrop-blur-md">
