                                        className={`px-4 py-2 rounded-xl text-sm font-bold whitespace-nowrap transition-all duration-300 flex-shrink-0 ${activeMseCategory === key ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/30 ring-1 ring-blue-400' : 'bg-white/30 text-slate-600 hover:bg-white/50 hover:text-slate-800'}`}
