const PsychNursingProV39 = () => {
  const [selectedFocus, setSelectedFocus] = useState('discharge_planning');
  const [selectedMSE, setSelectedMSE] = useState<string[]>([]);
  const [selectedSubjective, setSelectedSubjective] = useState<string[]>([]);
