            setRecord(prev => ({ ...prev, A: (prev.A ? prev.A + '\n' : '') + suggestions.join('\n') + "\n(AI 建議)", R: (prev.R ? prev.R.replace(/。$/, '，') : '') + " (請參考 AI 建議)。" }));
        }
    } catch (e) { alert("AI 連線失敗"); }
    setIsAiLoading(prev => ({ ...prev, a: false }));
  };

