                </div>
                <div className="glass-card rounded-2xl p-3 flex flex-col flex-1 min-h-[110px]">
                    <div className="mb-2 flex items-center gap-2">
                        <span className="text-xs font-bold text-emerald-600 bg-emerald-100/50 px-2 py-1 rounded-md">R: Response</span>
