                            <span className="text-xs font-bold text-blue-600 bg-blue-100/50 px-2 py-1 rounded-md">D: Data</span>
                            <button onClick={() => copySingle(record.D, 'D')} className="text-blue-500 hover:text-blue-700 transition-colors p-1 hover:bg-blue-100/50 rounded-md" title="複製內容"><Copy size={14}/></button>
                        </div>
                        <button onClick={handleAiPolishD} disabled={isAiLoading.d} className="text-xs text-blue-500 flex items-center gap-1 hover:bg-blue-50 rounded-full px-3 py-1 border">{isAiLoading.d ? <Loader2 className="animate-spin" size={12}/> : <Sparkles size={12}/>} 修飾</button>
                    </div>
                    <textarea value={record.D} onChange={e=>setRecord({...record,D:e.target.value})} className="w-full flex-1 text-base outline-none resize-none p-2 text-slate-700 bg-transparent" placeholder="輸入資料..."/>
