                        <button onClick={() => copySingle(record.A, 'A')} className="text-pink-500 hover:text-pink-700 transition-colors p-1 hover:bg-pink-100/50 rounded-md" title="複製內容"><Copy size={14}/></button>
                    </div>
                    <textarea value={record.A} onChange={e=>setRecord({...record,A:e.target.value})} className="w-full flex-1 text-base outline-none resize-none p-2 text-slate-700 bg-transparent" placeholder="輸入措施..."/>
                </div>
                <div className="glass-card rounded-2xl p-3 flex flex-col flex-1 min-h-[110px]">
                    <div className="mb-2 flex items-center gap-2">
                        <span className="text-xs font-bold text-emerald-600 bg-emerald-100/50 px-2 py-1 rounded-md">R: Response</span>
                        <button onClick={() => copySingle(record.R, 'R')} className="text-emerald-500 hover:text-emerald-700 transition-colors p-1 hover:bg-emerald-100/50 rounded-md" title="複製內容"><Copy size={14}/></button>
                    </div>
                    <textarea value={record.R} onChange={e=>setRecord({...record,R:e.target.value})} className="w-full flex-1 text-base outline-none resize-none p-2 text-slate-700 bg-transparent" placeholder="輸入評值..."/>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

