        }
    } catch (e) { alert("AI 連線失敗"); }
    setIsAiLoading(prev => ({ ...prev, a: false }));
  };

  const activeFocusData = selectedFocus === 'other_symptoms' ? OTHER_SYMPTOM_SUBTYPES[otherSymptomType] : NANDA_FOCUS_DATA[selectedFocus];
