                    <textarea value={record.R} onChange={e=>setRecord({...record,R:e.target.value})} className="w-full flex-1 text-base outline-none resize-none p-2 text-slate-700 bg-transparent" placeholder="輸入評值..."/>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

