                const items = MSE_COMMON_DATA[k].tags.filter(t => selectedMSE.includes(t.id)).map(t => t.text);
                if(items.length) obs.push(items.join('，'));
            });
            baseD += obs.length ? obs.join('，') + "。" : "精神狀況尚屬穩定。";
        }
