      <div className="mx-4 mt-4 mb-2 z-20 glass-panel rounded-2xl shrink-0">
          <div className="px-6 py-3 flex items-center justify-between gap-6">
            <div className="flex items-center gap-3 shrink-0">
                <div className="bg-gradient-to-tr from-green-400 to-teal-500 p-2 rounded-xl shadow-lg shadow-green-500/20"><Stethoscope className="text-white w-6 h-6" /></div>
                <div><h1 className="font-bold text-xl bg-clip-text text-transparent bg-gradient-to-r from-slate-800 to-slate-600 hidden md:block">精神科護理通</h1><span className="text-[10px] font-bold tracking-widest uppercase text-slate-400 hidden md:block">Pro V41.7 れんと</span></div>
            </div>
